// ===== EXTRACT ALL AD COPY — TITLES + BODY =====

function extractTitle(ad) {
  if (ad.headline && typeof ad.headline === 'object') {
    const t = ad.headline.title || ad.headline.description;
    if (t && !t.includes('{{')) return t;
  }
  if (ad.commentary && ad.commentary.text && !ad.commentary.text.includes('{{')) {
    return ad.commentary.text.substring(0, 150);
  }
  if (ad.snapshot) {
    if (Array.isArray(ad.snapshot.cards) && ad.snapshot.cards.length > 0) {
      for (const card of ad.snapshot.cards) {
        if (card.title && !card.title.includes('{{')) return card.title;
        if (card.body && typeof card.body === 'string' && !card.body.includes('{{')) return card.body.substring(0, 150);
      }
    }
    if (ad.snapshot.title && !ad.snapshot.title.includes('{{')) return ad.snapshot.title;
    if (ad.snapshot.body) {
      const bodyText = typeof ad.snapshot.body === 'object' ? ad.snapshot.body.text : ad.snapshot.body;
      if (bodyText && !bodyText.includes('{{')) return bodyText.substring(0, 150);
    }
  }
  if (typeof ad.title === 'string' && !ad.title.includes('{{')) return ad.title;
  if (typeof ad.ad_title === 'string' && ad.ad_title !== 'N/A') return ad.ad_title;
  return null;
}

function extractBody(ad) {
  if (ad.snapshot) {
    if (ad.snapshot.body) {
      const b = typeof ad.snapshot.body === 'object' ? ad.snapshot.body.text : ad.snapshot.body;
      if (b && b.length > 0) return b.substring(0, 400);
    }
    if (Array.isArray(ad.snapshot.cards) && ad.snapshot.cards.length > 0) {
      const bodies = ad.snapshot.cards
        .map(c => c.body || c.description || '')
        .filter(Boolean)
        .join(' | ');
      if (bodies) return bodies.substring(0, 400);
    }
  }
  if (ad.commentary && ad.commentary.text) return ad.commentary.text.substring(0, 400);
  if (ad.description) return String(ad.description).substring(0, 400);
  return '';
}

function getMonday(d) {
  const date = new Date(d);
  const day  = date.getDay();
  const diff = date.getDate() - day + (day === 0 ? -6 : 1);
  date.setDate(diff);
  return date.toISOString().split('T')[0];
}

const items = $input.all();
const weekOf = getMonday(new Date());
const adRows = [];

// Get domain + competitor_name from Loop node
let domain = '';
let competitorName = '';
try {
  const loopItem = $('Loop Over Competitors').item.json;
  domain         = loopItem.domain          || loopItem.Domain          || '';
  competitorName = loopItem.competitor_name || loopItem.Competitor_Name || loopItem.name || loopItem.Name || '';
} catch(e) {
  for (const item of items) {
    if (item.json.domain)          { domain         = item.json.domain; }
    if (item.json.competitor_name) { competitorName  = item.json.competitor_name; }
  }
}

for (const item of items) {
  const data = item.json;

  // Facebook/Meta
  if (data.results && Array.isArray(data.results)) {
    const fbAds = data.results.flat();
    for (const ad of fbAds) {
      const title = extractTitle(ad);
      if (!title) continue;
      adRows.push({
        domain,
        competitor_name: competitorName,
        week_of:         weekOf,
        platform:        'Meta',
        ad_title:        title,
        ad_body:         extractBody(ad)
      });
    }
  }

  // LinkedIn / Google
  if (data.ads && Array.isArray(data.ads)) {
    for (const ad of data.ads) {
      let platform = 'Google';
      if ((ad.view_details_link && ad.view_details_link.includes('linkedin.com')) || ad.headline || ad.commentary) {
        platform = 'LinkedIn';
      }
      const title = extractTitle(ad);
      if (!title) continue;
      adRows.push({
        domain,
        competitor_name: competitorName,
        week_of:         weekOf,
        platform,
        ad_title:        title,
        ad_body:         extractBody(ad)
      });
    }
  }
}

// Deduplicate by platform + title
const seen  = new Set();
const deduped = adRows.filter(r => {
  const key = `${r.platform}::${r.ad_title}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

if (deduped.length === 0) {
  return [{
    json: {
      domain,
      competitor_name: competitorName,
      week_of:         weekOf,
      ad_rows:         [],
      all_copy_text:   '',
      _no_ads:         true
    }
  }];
}

// Build a single aggregated copy blob for term extraction
const allCopyText = deduped
  .map(r => `${r.ad_title} ${r.ad_body}`)
  .join(' | ');

return [{
  json: {
    domain,
    competitor_name: competitorName,
    week_of:         weekOf,
    ad_rows:         deduped,
    all_copy_text:   allCopyText,
    _no_ads:         false
  }
}];

// ===== TERM EXTRACTION & DIFF AGAINST KNOWN TERMS =====
// Pure code — no AI. Fast, deterministic, cheap.

// ---------- CONFIG ----------
const MIN_ADS_FOR_SIGNAL    = 2;   // new term must appear in this many ads to be worth classifying
const MIN_TERM_LENGTH       = 3;   // ignore single chars / 2-char tokens
const MAX_TERM_WORDS        = 5;   // max words in a meaningful phrase

// Stopwords — extend this list freely
const STOPWORDS = new Set([
  'a','an','the','and','or','but','in','on','at','to','for','of','with',
  'by','from','is','are','was','were','be','been','being','have','has',
  'had','do','does','did','will','would','could','should','may','might',
  'shall','can','need','dare','ought','used','get','got','let','make',
  'your','our','their','its','my','his','her','we','you','they','it',
  'this','that','these','those','what','which','who','how','when','where',
  'why','all','more','most','some','any','each','every','both','few',
  'free','new','now','just','also','even','than','then','so','up','out',
  'about','into','through','during','before','after','above','below',
  'between','into','through','off','over','under','again','further',
  'here','there','once','s','t','re','ll','ve','d','m'
]);

function normalise(str) {
  return str
    .toLowerCase()
    .replace(/[^a-z0-9\s'\-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenise(text) {
  const words = normalise(text).split(' ').filter(w => w.length >= MIN_TERM_LENGTH && !STOPWORDS.has(w));
  const terms  = new Set();

  // Single meaningful words
  for (const w of words) {
    if (w.length >= MIN_TERM_LENGTH) terms.add(w);
  }

  // 2 to MAX_TERM_WORDS ngrams from original words array
  const allWords = normalise(text).split(' ');
  for (let n = 2; n <= MAX_TERM_WORDS; n++) {
    for (let i = 0; i <= allWords.length - n; i++) {
      const phrase = allWords.slice(i, i + n).join(' ');
      // Only keep phrases where at least one word is not a stopword
      const meaningful = allWords.slice(i, i + n).some(w => !STOPWORDS.has(w) && w.length >= MIN_TERM_LENGTH);
      if (meaningful && phrase.length >= MIN_TERM_LENGTH) {
        terms.add(phrase);
      }
    }
  }

  return terms;
}

// ---------- MAIN ----------

const allItems = $input.all();

// Get ad copy data from Extract All Ad Copy node
let adData = {};
try {
  adData = $('Extract All Ad Copy').first().json;
} catch(e) {
  return [{ json: { error: 'Could not read ad copy data', _skip: true } }];
}

const domain          = adData.domain          || '';
const competitorName  = adData.competitor_name || '';
const weekOf          = adData.week_of         || '';
const adRows          = adData.ad_rows         || [];

// If no ads this week, pass through skip sentinel
if (adData._no_ads || adRows.length === 0) {
  return [{
    json: {
      domain,
      competitor_name:  competitorName,
      week_of:          weekOf,
      new_terms:        [],
      term_ad_counts:   {},
      ad_rows:          [],
      _no_ads:          true,
      _skip:            true
    }
  }];
}

// Build known terms set from sheet rows
const knownTermsRows = allItems.map(i => i.json).filter(r => r.domain === domain && r.term);
const knownTermsSet  = new Set(knownTermsRows.map(r => String(r.term).toLowerCase().trim()));

// Extract all terms from this week's ads, track which ad each appears in
const termAdMap = {}; // term -> Set of ad_titles it appeared in

for (const ad of adRows) {
  const fullText = `${ad.ad_title} ${ad.ad_body}`;
  const terms    = tokenise(fullText);
  for (const term of terms) {
    if (!knownTermsSet.has(term)) {
      if (!termAdMap[term]) termAdMap[term] = new Set();
      termAdMap[term].add(ad.ad_title);
    }
  }
}

// Filter: only keep new terms appearing in MIN_ADS_FOR_SIGNAL or more ads
const qualifyingTerms = Object.entries(termAdMap)
  .filter(([term, adSet]) => adSet.size >= MIN_ADS_FOR_SIGNAL)
  .map(([term, adSet]) => ({
    term,
    times_seen:   adSet.size,
    seen_in_ads:  [...adSet].join('; ')
  }))
  .sort((a, b) => b.times_seen - a.times_seen);

// Build term ad counts map for downstream
const termAdCounts = {};
for (const t of qualifyingTerms) {
  termAdCounts[t.term] = t.times_seen;
}

// Total ads that contain at least one new qualifying term
const adsWithNewTerms = new Set();
for (const t of qualifyingTerms) {
  for (const adTitle of (termAdMap[t.term] || [])) {
    adsWithNewTerms.add(adTitle);
  }
}

// Build a text summary for the AI prompt
const termsSummary = qualifyingTerms.length > 0
  ? qualifyingTerms.map(t => `"${t.term}" (in ${t.times_seen} ads)`).join(', ')
  : 'None';

const thisWeekAdTitles = [...new Set(adRows.map(r => r.ad_title))].join('; ');

return [{
  json: {
    domain,
    competitor_name:          competitorName,
    week_of:                  weekOf,
    new_terms:                qualifyingTerms,
    term_ad_counts:           termAdCounts,
    ads_containing_new_terms: adsWithNewTerms.size,
    terms_summary:            termsSummary,
    this_week_ad_titles:      thisWeekAdTitles,
    all_copy_text:            adData.all_copy_text || '',
    ad_rows:                  adRows,
    known_terms_count:        knownTermsSet.size,
    _no_ads:                  false,
    _skip:                    qualifyingTerms.length === 0
  }
}];

