// 3-layer fallback: JSON parse → regex extraction → plain-text inference

const items = $input.all();
const data  = items[0].json;

let aiResult = {
  term_classifications: [],
  signal_detected:      false,
  signal_strength:      'Low',
  likely_launch_type:   'N/A',
  launch_name:          'N/A',
  evidence:             'N/A',
  recommended_action:   'N/A',
  signal_summary:       'N/A'
};

let rawText = '';
if (typeof data.output === 'string')     rawText = data.output;
else if (typeof data.text === 'string')  rawText = data.text;
else if (typeof data === 'string')       rawText = data;
else                                     rawText = JSON.stringify(data);

// Attempt 1: full JSON parse
let parsedOk = false;
try {
  const cleaned = rawText
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '')
    .trim();
  const start = cleaned.indexOf('{');
  const end   = cleaned.lastIndexOf('}');
  if (start !== -1 && end !== -1) {
    const parsed = JSON.parse(cleaned.substring(start, end + 1));
    if (parsed.signal_summary || parsed.signal_detected !== undefined) {
      aiResult.term_classifications = parsed.term_classifications || [];
      aiResult.signal_detected      = parsed.signal_detected      === true || parsed.signal_detected === 'true';
      aiResult.signal_strength      = parsed.signal_strength      || 'Low';
      aiResult.likely_launch_type   = parsed.likely_launch_type   || 'N/A';
      aiResult.launch_name          = parsed.launch_name          || 'N/A';
      aiResult.evidence             = parsed.evidence             || 'N/A';
      aiResult.recommended_action   = parsed.recommended_action   || 'N/A';
      aiResult.signal_summary       = parsed.signal_summary       || 'N/A';
      parsedOk = true;
    }
  }
} catch(e) {}

// Attempt 2: regex field extraction
if (!parsedOk) {
  function extract(text, field) {
    const re = new RegExp('"' + field + '"\\s*:\\s*"([^"]+)"');
    const m  = text.match(re);
    return m ? m[1] : null;
  }
  function extractBool(text, field) {
    const re = new RegExp('"' + field + '"\\s*:\\s*(true|false)');
    const m  = text.match(re);
    return m ? m[1] === 'true' : null;
  }

  aiResult.signal_detected    = extractBool(rawText, 'signal_detected')  ?? aiResult.signal_detected;
  aiResult.signal_strength    = extract(rawText, 'signal_strength')       || aiResult.signal_strength;
  aiResult.likely_launch_type = extract(rawText, 'likely_launch_type')    || aiResult.likely_launch_type;
  aiResult.launch_name        = extract(rawText, 'launch_name')           || aiResult.launch_name;
  aiResult.evidence           = extract(rawText, 'evidence')              || aiResult.evidence;
  aiResult.recommended_action = extract(rawText, 'recommended_action')    || aiResult.recommended_action;
  aiResult.signal_summary     = extract(rawText, 'signal_summary')        || aiResult.signal_summary;

  // Try to parse term_classifications array
  try {
    const arrMatch = rawText.match(/"term_classifications"\s*:\s*(\[.*?\])/s);
    if (arrMatch) {
      aiResult.term_classifications = JSON.parse(arrMatch[1]);
    }
  } catch(e) {}
}

// Attempt 3: plain-text fallback — use full output as signal_summary
if (aiResult.signal_summary === 'N/A' && rawText.length > 10) {
  aiResult.signal_summary = rawText.trim().substring(0, 400);
  const lower = rawText.toLowerCase();
  if (lower.includes('product') || lower.includes('launch') || lower.includes('new feature')) {
    aiResult.signal_detected    = true;
    aiResult.likely_launch_type = lower.includes('product') ? 'New Product' : 'New Feature';
  }
  if (lower.includes('high')) {
    aiResult.signal_strength = 'High';
  } else if (lower.includes('medium') || lower.includes('moderate')) {
