} catch(e) {}

const domain          = termData.domain          || '';
const competitorName  = termData.competitor_name || '';
const weekOf          = termData.week_of         || '';
const newTerms        = (termData.new_terms || []).map(t => t.term).join('; ') || 'None';
const termCount       = (termData.new_terms || []).length;
const adsWithTerms    = termData.ads_containing_new_terms || 0;

// Build enriched term rows for known_terms sheet
